mapper.select:
SELECT * FROM im_message
WHERE conversation_id = #{conversationId}
ORDER BY send_time DESC
LIMIT #{offset}, #{limit}

mapper.update:
UPDATE im_message SET status = 'DELIVERED'
WHERE id IN

    #{id}

UPDATE im_message SET status = 'READ'
WHERE conversation_id = #{conversationId}
  AND sender_id != #{userId}
  AND status != 'READ'

mapper.select:
SELECT COUNT(*) FROM im_message m
INNER JOIN im_conversation_member cm ON m.conversation_id = cm.conversation_id
WHERE cm.user_id = #{userId}
  AND m.sender_id != #{userId}
  AND m.status != 'READ'
